partner_table                                                │\\n├─────────────────────────────────────────────────────────────┤\\n│ partnerId (PK)    │ String - Unique identifier              │\\n│ name              │ String - Partner name                   │\\n│ createdAt         │ String - ISO timestamp                  │\\n│ updatedAt         │ String - ISO timestamp                  │\\n│ createdBy         │ String - User who created               │\\n└─────────────────────────────────────────────────────────────┘","type":"text","styles":{}}],"children":[]},{"id":"fef45a2b-a69d-4eb8-8035-5ae83aa6a7ab","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Key Points","type":"text","styles":{"bold":true}},{"text":":","type":"text","styles":{}}],"children":[]},{"id":"f7336833-01cf-4885-917f-a5446b9d6792","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Separate table for Partners only","type":"text","styles":{}}],"children":[]},{"id":"b5dded79-99f7-4d3f-bfc1-1db32353429d","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Simpler schema without type differentiation","type":"text","styles":{}}],"children":[]},{"id":"b9737454-165b-47ac-ab6e-737126b5e5af","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"No parent relationships (Partners are top-level)","type":"text","styles":{}}],"children":[]},{"id":"e4376006-4424-48dd-acd1-172e8e41ed2e","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"2. Client Table (","type":"text","styles":{}},{"text":"client_table","type":"text","styles":{"code":true}},{"text":")","type":"text","styles":{}}],"children":[]},{"id":"15e9b972-25ca-4967-b44b-ad9a0dae1c64","type":"codeBlock","props":{"language":"text"},"content":[{"text":"┌─────────────────────────────────────────────────────────────┐\\n│ client_table                                                 │\\n├─────────────────────────────────────────────────────────────┤\\n│ clientId (PK)     │ String - Unique identifier              │\\n│ partnerId         │ String - REQUIRED - Parent Partner ID   │\\n│ name              │ String - Client name                    │\\n│ createdAt         │ String - ISO timestamp                  │\\n│ updatedAt         │ String - ISO timestamp                  │\\n│ createdBy         │ String - User who created               │\\n├─────────────────────────────────────────────────────────────┤\\n│ GSI: clientByPartnerIdIndex (partnerId as HASH)             │\\n│   - For: \\"List all Clients under a Partner\\"                  │\\n└─────────────────────────────────────────────────────────────┘","type":"text","styles":{}}],"children":[]},{"id":"2875cf67-95d9-4560-aff2-cc977c75f3c3","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Key Points","type":"text","styles":{"bold":true}},{"text":":","type":"text","styles":{}}],"children":[]},{"id":"34109c38-dbdc-4f49-bc4e-7154b1ff87cb","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Only stores Clients (not Partners)","type":"text","styles":{}}],"children":[]},{"id":"3ec4072e-c602-429c-a9d5-46cf9d1803bc","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" is ","type":"text","styles":{}},{"text":"required","type":"text","styles":{"bold":true}},{"text":" - every Client belongs to a Partner","type":"text","styles":{}}],"children":[]},{"id":"ea25cb07-3631-42a2-9df1-406ac899cae1","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Simpler schema without type field","type":"text","styles":{}}],"children":[]},{"id":"6fd356fb-fb4e-42b1-9fc6-8726c64fea19","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"4. Organization Table","type":"text","styles":{}}],"children":[]},{"id":"d94eda69-5e3e-46ba-9dc6-cc3faf3e5b59","type":"codeBlock","props":{"language":"text"},"content":[{"text":"┌─────────────────────────────────────────────────────────────┐\\n│ Organization Table                                           │\\n├─────────────────────────────────────────────────────────────┤\\n│ orgId (PK)        │ String - Unique identifier              │\\n│ partnerId         │ String - REQUIRED - Parent Partner      │\\n│ clientId          │ String | null - Optional Client         │\\n│ name              │ String - Organization name              │\\n│ ... other fields                                             │\\n├─────────────────────────────────────────────────────────────┤\\n│ GSI 1: orgByPartnerIdIndex (partnerId as HASH)              │\\n│   - For: \\"Get all orgs under a Partner\\"                      │\\n│ GSI 2: orgByClientIdIndex (clientId as HASH)                │\\n│   - For: \\"Get all orgs under a Client\\"                       │\\n└─────────────────────────────────────────────────────────────┘","type":"text","styles":{}}],"children":[]},{"id":"87a9fe37-27c2-47ae-a2ce-9e98059221f4","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Key Points","type":"text","styles":{"bold":true}},{"text":":","type":"text","styles":{}}],"children":[]},{"id":"72f22289-6df1-4730-b93a-1a530f6e4105","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" is ","type":"text","styles":{}},{"text":"required","type":"text","styles":{"bold":true}},{"text":" - every org belongs to a Partner","type":"text","styles":{}}],"children":[]},{"id":"a749c4e1-9e53-4b67-bfea-e788ad78f1c7","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"clientId","type":"text","styles":{"code":true}},{"text":" is ","type":"text","styles":{}},{"text":"optional","type":"text","styles":{"bold":true}},{"text":" - org can be directly under Partner or under a Client","type":"text","styles":{}}],"children":[]},{"id":"8b0b1335-874a-4d08-9fa1-b5e1e398bd72","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"No ","type":"text","styles":{"bold":true}},{"text":"org_access","type":"text","styles":{"code":true}},{"text":" table needed","type":"text","styles":{"bold":true}},{"text":" - access determined by hierarchical relationships","type":"text","styles":{}}],"children":[]},{"id":"b23c534c-8a00-45a9-b3d5-74f7c5912f55","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"5. User Table","type":"text","styles":{}}],"children":[]},{"id":"eb9bf177-e888-4dd5-8b91-0c1e83af84ea","type":"codeBlock","props":{"language":"text"},"content":[{"text":"┌─────────────────────────────────────────────────────────────┐\\n│ User Table (admin users with orgId = \\"GLOBAL_ADMIN\\")        │\\n├─────────────────────────────────────────────────────────────┤\\n│ userId (SK)       │ String                                   │\\n│ orgId (PK)        │ \\"GLOBAL_ADMIN\\" for admin users          │\\n│ email             │ String                                   │\\n│ userRole          │ ''VardaCareAdmin'' | ''ClientAdmin'' | ''SuperAdmin'' │\\n│ partnerId         │ String | null - For PartnerAdmin only   │\\n│ clientId          │ String | null - For ClientAdmin only    │\\n│ allowedOrgIds     │ string[] - For SuperAdmin only          │\\n│ permissions       │ { canCreateOrg: boolean; ... }          │\\n│ status            │ ''ACTIVE'' | ''INACTIVE'' | ''SUSPENDED''     │\\n│ ... other fields                                             │\\n└─────────────────────────────────────────────────────────────┘","type":"text","styles":{}}],"children":[]},{"id":"32f73546-b906-475b-b7f1-6bf46889cf20","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Key Points","type":"text","styles":{"bold":true}},{"text":":","type":"text","styles":{}}],"children":[]},{"id":"e38096ea-fe77-4a78-b403-18cdf50475b5","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"PartnerAdmin","type":"text","styles":{"bold":true}},{"text":" (ClientAdmin with ","type":"text","styles":{}},{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" populated): Can access orgs via ","type":"text","styles":{}},{"text":"org.partnerId","type":"text","styles":{"code":true}},{"text":" or ","type":"text","styles":{}},{"text":"client.partnerId","type":"text","styles":{"code":true}},{"text":" relationships","type":"text","styles":{}}],"children":[]},{"id":"54133241-a24a-4511-bcc5-16ec180564fd","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"ClientAdmin","type":"text","styles":{"bold":true}},{"text":" (ClientAdmin with ","type":"text","styles":{}},{"text":"clientId","type":"text","styles":{"code":true}},{"text":" populated): Can access orgs via ","type":"text","styles":{}},{"text":"org.clientId","type":"text","styles":{"code":true}},{"text":" relationship","type":"text","styles":{}}],"children":[]},{"id":"0c03f8d5-832c-4885-983a-3b9aad1965e7","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"SuperAdmin","type":"text","styles":{"code":true}},{"text":" users: ","type":"text","styles":{}},{"text":"allowedOrgIds","type":"text","styles":{"code":true}},{"text":" array for manual selection","type":"text","styles":{}}],"children":[]},{"id":"d498cc33-53a6-47c0-92c8-552b7e275618","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"VardaCareAdmin","type":"text","styles":{"code":true}},{"text":": No access scope fields needed (full access)","type":"text","styles":{}}],"children":[]},{"id":"ae756bfa-413f-4719-9a99-7487e7f4afe1","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" and ","type":"text","styles":{}},{"text":"clientId","type":"text","styles":{"code":true}},{"text":" are mutually exclusive for ","type":"text","styles":{}},{"text":"ClientAdmin","type":"text","styles":{"code":true}},{"text":" role","type":"text","styles":{}}],"children":[]},{"id":"07b6c115-13f3-43f8-9750-bafa41c1d3cf","type":"divider","props":{},"children":[]},{"id":"6cc0328a-4f6e-42d2-8ea9-bb45036ab0eb","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Permission Handler Flows","type":"text","styles":{}}],"children":[]},{"id":"516208d0-5f94-4b67-8fda-86c0eb5b2571","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"1. Check Single Org Access","type":"text","styles":{}}],"children":[]},{"id":"45576900-ed26-47b2-921e-6fa7cdc60858","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"VardaCareAdmin","type":"text","styles":{}}],"children":[]},{"id":"01ace31d-b884-4ae1-95ce-3dad2697efaa","type":"codeBlock","props":{"language":"mermaid"},"content":[{"text":"sequenceDiagram\\n    participant User as VardaCareAdmin\\n    participant PH as Permission Handler\\n    participant UserTable as Users Table\\n\\n    User->>PH: Request with orgId\\n    PH->>UserTable: getAdminUser(email)\\n    UserTable-->>PH: adminUser (userRole = \\"VardaCareAdmin\\")\\n\\n    Note over PH: Full access - no check needed\\n    PH-->>User: Access granted ✓ (0 queries)","type":"text","styles":{}}],"children":[]},{"id":"ab4883f4-5b02-4248-aa17-55ed78b129bd","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"ClientAdmin (Partner User)","type":"text","styles":{}}],"children":[]},{"id":"91f70bd0-af6e-44d0-b19a-6b137e1fa111","type":"codeBlock","props":{"language":"mermaid"},"content":[{"text":"sequenceDiagram\\n    participant User as PartnerAdmin\\n    participant PH as Permission Handler\\n    participant UserTable as Users Table\\n    participant OrgTable as Organization Table\\n    participant ClientTable as Client Table\\n\\n    User->>PH: Request with orgId = \\"org_1\\"\\n    PH->>UserTable: getAdminUser(email)\\n    UserTable-->>PH: adminUser (userRole = \\"ClientAdmin\\", partnerId = \\"partner_A\\")\\n\\n    Note over PH: Check hierarchical access\\n    PH->>OrgTable: GetItem (orgId = \\"org_1\\")\\n    OrgTable-->>PH: org (partnerId = \\"partner_A\\", clientId = \\"client_X\\")\\n\\n    alt org.partnerId === user.partnerId\\n        PH-->>User: Access granted ✓ (1 query - direct org)\\n    else org.clientId exists\\n        PH->>ClientTable: GetItem (clientId = \\"client_X\\")\\n        ClientTable-->>PH: client (partnerId = \\"partner_A\\")\\n        alt client.partnerId === user.partnerId\\n            PH-->>User: Access granted ✓ (2 queries - via client)\\n        else\\n            PH-->>User: Access denied ✗\\n        end\\n    else\\n        PH-->>User: Access denied ✗\\n    end","type":"text","styles":{}}],"children":[]},{"id":"cac4a605-e508-4c4b-a2d5-96631dc3528c","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"ClientAdmin (Client User)","type":"text","styles":{}}],"children":[]},{"id":"9e22f2a0-e79f-4923-ad33-cc27db2ae831","type":"codeBlock","props":{"language":"mermaid"},"content":[{"text":"sequenceDiagram\\n    participant User as ClientAdmin\\n    participant PH as Permission Handler\\n    participant UserTable as Users Table\\n    participant OrgTable as Organization Table\\n\\n    User->>PH: Request with orgId = \\"org_1\\"\\n    PH->>UserTable: getAdminUser(email)\\n    UserTable-->>PH: adminUser (userRole = \\"ClientAdmin\\", clientId = \\"client_X\\")\\n\\n    Note over PH: Check clientId match\\n    PH->>OrgTable: GetItem (orgId = \\"org_1\\")\\n    OrgTable-->>PH: org (clientId = \\"client_X\\")\\n\\n    alt org.clientId === user.clientId\\n        PH-->>User: Access granted ✓ (1 query)\\n    else\\n        PH-->>User: Access denied ✗\\n    end","type":"text","styles":{}}],"children":[]},{"id":"ee31e86f-5837-4680-9675-b5d32d507f2d","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"SuperAdmin","type":"text","styles":{}}],"children":[]},{"id":"8d8f19ed-6ab3-4f20-8bc1-915f93243489","type":"codeBlock","props":{"language":"mermaid"},"content":[{"text":"sequenceDiagram\\n    participant User as SuperAdmin\\n    participant PH as Permission Handler\\n    participant UserTable as Users Table\\n\\n    User->>PH: Request with orgId = \\"org_5\\"\\n    PH->>UserTable: getAdminUser(email)\\n    UserTable-->>PH: adminUser (userRole = \\"SuperAdmin\\", allowedOrgIds = [\\"org_1\\", \\"org_5\\"])\\n\\n    Note over PH: Check allowedOrgIds array (in-memory)\\n    PH->>PH: \\"org_5\\" in allowedOrgIds?\\n\\n    alt orgId in allowedOrgIds\\n        PH-->>User: Access granted ✓ (0 queries)\\n    else Not in list\\n        PH-->>User: Access denied ✗\\n    end","type":"text","styles":{}}],"children":[]},{"id":"2275ff78-4299-4d6e-bfc2-33386622ea15","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"2. Get All Orgs","type":"text","styles":{}}],"children":[]},{"id":"0d4560b3-5bb6-4cfa-89d0-952d3ec0358c","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"VardaCareAdmin","type":"text","styles":{}}],"children":[]},{"id":"233a79e0-96de-40ab-a9c6-eb5fd0875a4c","type":"codeBlock","props":{"language":"mermaid"},"content":[{"text":"sequenceDiagram\\n    participant User as VardaCareAdmin\\n    participant PH as Permission Handler\\n    participant OrgTable as Organization Table\\n\\n    User->>PH: getAllOrgs request\\n    PH->>OrgTable: Scan all organizations\\n    OrgTable-->>PH: All orgs\\n    PH-->>User: Return all orgs (1 query)","type":"text","styles":{}}],"children":[]},{"id":"b3a1ff6b-65bb-489e-afff-260dab225c5b","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"PartnerAdmin (ClientAdmin with partnerId)","type":"text","styles":{}}],"children":[]},{"id":"ea5416b6-ef1f-4f76-bf26-69eedf68a788","type":"codeBlock","props":{"language":"mermaid"},"content":[{"text":"sequenceDiagram\\n    participant User as PartnerAdmin\\n    participant PH as Permission Handler\\n    participant UserTable as Users Table\\n    participant OrgTable as Organization Table\\n    participant ClientTable as Client Table\\n\\n    User->>PH: getAllOrgs request\\n    PH->>UserTable: getAdminUser(email)\\n    UserTable-->>PH: adminUser (partnerId = \\"partner_A\\")\\n\\n    Note over PH: Get direct orgs under partner\\n    PH->>OrgTable: Query GSI by partnerId = \\"partner_A\\"\\n    OrgTable-->>PH: [org_1, org_2] (direct orgs)\\n\\n    Note over PH: Get client orgs\\n    PH->>ClientTable: Query GSI by partnerId = \\"partner_A\\"\\n    ClientTable-->>PH: [client_X, client_Y]\\n\\n    loop For each client\\n        PH->>OrgTable: Query GSI by clientId\\n        OrgTable-->>PH: [org_3, org_4] (client orgs)\\n    end\\n\\n    PH->>PH: Merge and deduplicate orgs\\n    PH-->>User: Return orgs (1 + N queries, N = number of clients)","type":"text","styles":{}}],"children":[]},{"id":"931253a1-7026-4d6c-91c9-be950214570b","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"ClientAdmin (Client User)","type":"text","styles":{}}],"children":[]},{"id":"749dc6d1-c77d-4033-b337-247eac9ad15a","type":"codeBlock","props":{"language":"mermaid"},"content":[{"text":"sequenceDiagram\\n    participant User as ClientAdmin\\n    participant PH as Permission Handler\\n    participant UserTable as Users Table\\n    participant OrgTable as Organization Table\\n\\n    User->>PH: getAllOrgs request\\n    PH->>UserTable: getAdminUser(email)\\n    UserTable-->>PH: adminUser (clientId = \\"client_X\\")\\n\\n    Note over PH: Get orgs by clientId\\n    PH->>OrgTable: Query GSI by clientId = \\"client_X\\"\\n    OrgTable-->>PH: [org_3, org_4, org_5]\\n\\n    PH-->>User: Return orgs (1 query)","type":"text","styles":{}}],"children":[]},{"id":"303b760b-5aeb-4ac4-b4b2-b2c4dd74e983","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"SuperAdmin","type":"text","styles":{}}],"children":[]},{"id":"09ec158f-f576-4fba-ba9d-f07fd19cce23","type":"codeBlock","props":{"language":"mermaid"},"content":[{"text":"sequenceDiagram\\n    participant User as SuperAdmin\\n    participant PH as Permission Handler\\n    participant UserTable as Users Table\\n    participant OrgTable as Organization Table\\n\\n    User->>PH: getAllOrgs request\\n    PH->>UserTable: getAdminUser(email)\\n    UserTable-->>PH: adminUser (allowedOrgIds = [\\"org_1\\", \\"org_5\\"])\\n\\n    PH->>OrgTable: BatchGetItem by orgIds\\n    OrgTable-->>PH: [org_1, org_5]\\n\\n    PH-->>User: Return orgs (1 query)","type":"text","styles":{}}],"children":[]},{"id":"af9fd663-4956-427a-af88-9caefe820956","type":"divider","props":{},"children":[]},{"id":"aa21d59a-842e-4e24-be7d-b884eed9a868","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Permission Handler Implementation","type":"text","styles":{}}],"children":[]},{"id":"5df33890-c43d-435f-9ca2-634def46bf44","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Access Check Function","type":"text","styles":{}}],"children":[]},{"id":"6a8f1b67-e27a-45fe-9be0-82fe70007f49","type":"codeBlock","props":{"language":"typescript"},"content":[{"text":"async function hasOrgAccess(\\n  adminUser: AdminUser,\\n  targetOrgId: string\\n): Promise<boolean> {\\n  switch (adminUser.userRole) {\\n    case \\"VardaCareAdmin\\":\\n      // Full access - no check needed\\n      return true;\\n\\n    case \\"ClientAdmin\\":\\n      const org = await getItem(\\"Organization\\", { orgId: targetOrgId });\\n      if (!org) return false;\\n\\n      // PartnerAdmin: Check if org belongs to partner directly or via client\\n      if (adminUser.partnerId) {\\n        if (org.partnerId === adminUser.partnerId) {\\n          return true; // Direct org access\\n        }\\n        if (org.clientId) {\\n          // Check if client belongs to this partner\\n          const client = await getItem(\\"client_table\\", {\\n            clientId: org.clientId,\\n          });\\n          return client?.partnerId === adminUser.partnerId;\\n        }\\n        return false;\\n      }\\n\\n      // ClientAdmin: Check if org belongs to client\\n      if (adminUser.clientId) {\\n        return org.clientId === adminUser.clientId;\\n      }\\n\\n      return false;\\n\\n    case \\"SuperAdmin\\":\\n      // Check allowedOrgIds array (in-memory)\\n      return adminUser.allowedOrgIds.includes(targetOrgId);\\n\\n    default:\\n      return false;\\n  }\\n}","type":"text","styles":{}}],"children":[]},{"id":"ef97523e-6c45-44ce-b677-da6a47770e24","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Get Allowed Orgs Function","type":"text","styles":{}}],"children":[]},{"id":"4c1ab92f-2f25-4731-9610-5ac41cba1dcd","type":"codeBlock","props":{"language":"typescript"},"content":[{"text":"async function getAllowedOrgs(adminUser: AdminUser): Promise<Organization[]> {\\n  switch (adminUser.userRole) {\\n    case \\"VardaCareAdmin\\":\\n      // Return all orgs\\n      return await scanAllOrgs();\\n\\n    case \\"ClientAdmin\\":\\n      // PartnerAdmin: Get direct orgs + client orgs\\n      if (adminUser.partnerId) {\\n        // Get direct orgs under partner\\n        const directOrgs = await queryOrgsByPartnerId(adminUser.partnerId);\\n\\n        // Get all clients under partner\\n        const clients = await queryClientsByPartnerId(adminUser.partnerId);\\n\\n        // Get orgs for each client\\n        const clientOrgPromises = clients.map((client) =>\\n          queryOrgsByClientId(client.clientId)\\n        );\\n        const clientOrgsArrays = await Promise.all(clientOrgPromises);\\n        const clientOrgs = clientOrgsArrays.flat();\\n\\n        // Merge and deduplicate\\n        const allOrgIds = new Set([\\n          ...directOrgs.map((o) => o.orgId),\\n          ...clientOrgs.map((o) => o.orgId),\\n        ]);\\n        return await batchGetOrgs(Array.from(allOrgIds));\\n      }\\n\\n      // ClientAdmin: Get orgs by clientId\\n      if (adminUser.clientId) {\\n        return await queryOrgsByClientId(adminUser.clientId);\\n      }\\n\\n      return [];\\n\\n    case \\"SuperAdmin\\":\\n      // Batch get by allowedOrgIds\\n      return await batchGetOrgs(adminUser.allowedOrgIds);\\n\\n    default:\\n      return [];\\n  }\\n}","type":"text","styles":{}}],"children":[]},{"id":"08f5181f-8091-41ec-bddc-72e4c2da4343","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Performance Summary","type":"text","styles":{}}],"children":[]},{"id":"6da6c21a-a790-4a40-9f63-276a5025150c","type":"table","props":{"textColor":"default"},"content":{"rows":[{"cells":[{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Role","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Check Org Access","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Get All Orgs","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Complexity","type":"text","styles":{}}]}]},{"cells":[{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"VardaCareAdmin","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"0 queries","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"1 query (scan)","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Simple","type":"text","styles":{}}]}]},{"cells":[{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"PartnerAdmin","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"1-2 queries (hierarchical)","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"1 + N queries (N = clients)","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Medium","type":"text","styles":{}}]}]},{"cells":[{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"ClientAdmin","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"1 query","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"1 query (GSI)","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Simple","type":"text","styles":{}}]}]},{"cells":[{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"SuperAdmin","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"0 queries","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"1 query (batch)","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Simple","type":"text","styles":{}}]}]}],"type":"tableContent","headerRows":1,"columnWidths":[null,null,null,null]},"children":[]},{"id":"e916f1b2-f0b4-40d9-b43c-5604d7da79a4","type":"divider","props":{},"children":[]},{"id":"c791c2f1-e7bc-4a46-8ff9-492fe8452c02","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Query Endpoints Updates","type":"text","styles":{}}],"children":[]},{"id":"7a412166-9d70-4504-a5a1-50d880857e1b","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"getAllOrgs (for PartnerAdmin)","type":"text","styles":{}}],"children":[]},{"id":"2f1515fb-621e-404b-aeaf-eb97844148e6","type":"codeBlock","props":{"language":"text"},"content":[{"text":"1. Get user''s partnerId from User table\\n2. Query orgs by partnerId (GSI query) - direct orgs\\n3. Query clients by partnerId (GSI query) - get all clients\\n4. For each client: Query orgs by clientId (GSI query)\\n5. Merge and deduplicate\\n6. Return combined org list","type":"text","styles":{}}],"children":[]},{"id":"b8bf2844-055b-42bc-8068-68f44915ec3d","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"getAllOrgs (for ClientAdmin)","type":"text","styles":{}}],"children":[]},{"id":"2764e572-dc8b-47f2-b9a1-b108a43d2ea4","type":"codeBlock","props":{"language":"text"},"content":[{"text":"1. Get user''s clientId from User table\\n2. Query orgs by clientId (GSI query)\\n3. Return org list","type":"text","styles":{}}],"children":[]},{"id":"85f2c4d2-35ab-4a2e-9673-e92aaeb80909","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"getAllClients (for PartnerAdmin)","type":"text","styles":{}}],"children":[]},{"id":"88feec7e-bb21-44d2-8bf5-17372912d9b6","type":"codeBlock","props":{"language":"text"},"content":[{"text":"1. Get user''s partnerId from User table\\n2. Query clients by partnerId (GSI query)\\n3. Return client list","type":"text","styles":{}}],"children":[]},{"id":"7991836c-9157-4549-a52b-190a65eb7061","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"getAllPartners (Platform Users only)","type":"text","styles":{}}],"children":[]},{"id":"5f359eb0-2a18-4312-8665-6bb4cd060c9b","type":"codeBlock","props":{"language":"text"},"content":[{"text":"1. Verify user is VardaCareAdmin\\n2. Scan partner_table\\n3. Return all partners","type":"text","styles":{}}],"children":[]},{"id":"44e9c710-c0b1-4ba5-9d6c-080f3828fded","type":"divider","props":{},"children":[]},{"id":"7a8e4161-4df8-4273-bc65-aa2005879df4","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Entity Management Capabilities","type":"text","styles":{}}],"children":[]},{"id":"7914834b-17c7-4934-9fe8-c4f5e6a8e79d","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"VardaCareAdmin (Platform User)","type":"text","styles":{}}],"children":[]},{"id":"fd8fb44c-8c2c-