ll","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Full management","type":"text","styles":{}}]}]},{"cells":[{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Create Admin Users","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"✓","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Can create VardaCareAdmin, ClientAdmin, SuperAdmin","type":"text","styles":{}}]}]}],"type":"tableContent","headerRows":1,"columnWidths":[null,null,null]},"children":[]},{"id":"9c90e338-eccb-40f2-8a56-a386cd6cb58f","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"ClientAdmin (Partner or Client User)","type":"text","styles":{}}],"children":[]},{"id":"7bc95c8e-b535-41ce-8c8b-81565d66242e","type":"table","props":{"textColor":"default"},"content":{"rows":[{"cells":[{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Action","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Allowed","type":"text","styles":{}}]},{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Notes","type":"text","styles":{}}]}]},{"cells":[{"type":"tableCell","props":{"colspan":1,"rowspan":1,"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Create Part