lor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Add ","type":"text","styles":{}},{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" field (required)","type":"text","styles":{}}],"children":[]},{"id":"b6377fef-fed0-495f-ba00-c2df7c6aadf4","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Add ","type":"text","styles":{}},{"text":"clientId","type":"text","styles":{"code":true}},{"text":" field (optional)","type":"text","styles":{}}],"children":[]},{"id":"f497ffbc-cbfc-4367-bfcb-f0f016eaffa5","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Add GSI: ","type":"text","styles":{}},{"text":"orgByPartnerIdIndex","type":"text","styles":{"code":true}},{"text":" (partnerId as HASH)","type":"text","styles":{}}],"children":[]},{"id":"8991aaa9-9057-497a-8f55-f2489b40577f","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Add GSI: ","type":"text","styles":{}},{"text":"orgByClientIdIndex","type":"text","styles":{"code":true}},{"text":" (clientId as HASH)","type":"text","styles":{}}],"children":[]}]},{"id":"79cb9c40-78f2-4473-b9be-acdc3fcf4ba0","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"User Table","type":"text","styles":{"bold":true}},{"text":" (UPDATED):","type":"text","styles":{}}],"children":[{"id":"9decd291-1fea-4b4d-8320-1cce62744a96","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Add ","type":"text","styles":{}},{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" field (for PartnerAdmin users)","type":"text","styles":{}}],"children":[]},{"id":"96cbdf18-0f81-422c-8069-0f43edeef5dd","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Add ","type":"text","styles":{}},{"text":"clientId","type":"text","styles":{"code":true}},{"text":" field (for ClientAdmin users)","type":"text","styles":{}}],"children":[]},{"id":"3136ee28-bdc0-4ab3-8fad-b39da526e290","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" and ","type":"text","styles":{}},{"text":"clientId","type":"text","styles":{"code":true}},{"text":" are mutually exclusive for ","type":"text","styles":{}},{"text":"ClientAdmin","type":"text","styles":{"code":true}},{"text":" role","type":"text","styles":{}}],"children":[]}]},{"id":"6c3bb79d-1fbe-41c8-9ddc-4b215e300b2e","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Cognito Groups to Create","type":"text","styles":{}}],"children":[]},{"id":"db41c5a1-14ee-47f1-92ca-67326ad76569","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"New","type":"text","styles":{"bold":true}},{"text":": ","type":"text","styles":{}},{"text":"ClientAdmin","type":"text","styles":{"code":true}},{"text":" group (used for both Partner and Client users)","type":"text","styles":{}}],"children":[]},{"id":"8c1da721-d0b6-47c5-8c9a-351e80cc788b","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"userRole.ts Updates","type":"text","styles":{}}],"children":[]},{"id":"d0d54aa1-32da-407a-b212-fd03dfda4e9c","type":"codeBlock","props":{"language":"typescript"},"content":[{"text":"export enum CognitoUserRoles {\\n  superAdmin = \\"SuperAdmin\\",\\n  employee = \\"Employee\\",\\n  organisationAdmin = \\"Admin\\",\\n  vardacareAdmin = \\"VardaCareAdmin\\",\\n  systemAdmin = \\"SystemAdmin\\",\\n  clientAdmin = \\"ClientAdmin\\", // NEW - used for both Partner and Client users\\n  default = \\"Default\\",\\n}","type":"text","styles":{}}],"children":[]},{"id":"ca60792f-91fe-42c9-bb91-966556ea2c92","type":"divider","props":{},"children":[]},{"id":"91e23475-266a-4723-876f-56243f936fe1","type":"divider","props":{},"children":[]},{"id":"90e3701d-15e6-4603-8d74-0d689985977a","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Complete Permission Handler Implementation","type":"text","styles":{}}],"children":[]},{"id":"aa5c7391-caae-4ac1-ae56-1ac2fab47163","type":"codeBlock","props":{"language":"typescript"},"content":[{"text":"// Permission Handler - Complete Implementation\\n\\nasync function hasOrgAccess(\\n  adminUser: AdminUser,\\n  targetOrgId: string\\n): Promise<boolean> {\\n  switch (adminUser.userRole) {\\n    case \\"VardaCareAdmin\\":\\n      return true; // Full access - no check needed\\n\\n    case \\"ClientAdmin\\":\\n      const org = await getItem(\\"Organization\\", { orgId: targetOrgId });\\n      if (!org) return false;\\n\\n      // PartnerAdmin: Check if org belongs to partner directly or via client\\n      if (adminUser.partnerId) {\\n        if (org.partnerId === adminUser.partnerId) {\\n          return true; // Direct org access\\n        }\\n        if (org.clientId) {\\n          // Check if client belongs to this partner\\n          const client = await getItem(\\"client_table\\", {\\n            clientId: org.clientId,\\n          });\\n          return client?.partnerId === adminUser.partnerId;\\n        }\\n        return false;\\n      }\\n\\n      // ClientAdmin: Check if org belongs to client\\n      if (adminUser.clientId) {\\n        return org.clientId === adminUser.clientId;\\n      }\\n\\n      return false;\\n\\n    case \\"SuperAdmin\\":\\n      // Check allowedOrgIds array (in-memory)\\n      return adminUser.allowedOrgIds.includes(targetOrgId);\\n\\n    default:\\n      return false;\\n  }\\n}\\n\\nasync function getAllowedOrgs(adminUser: AdminUser): Promise<Organization[]> {\\n  switch (adminUser.userRole) {\\n    case \\"VardaCareAdmin\\":\\n      return await scanAllOrgs();\\n\\n    case \\"ClientAdmin\\":\\n      // PartnerAdmin: Get direct orgs + client orgs\\n      if (adminUser.partnerId) {\\n        // Get direct orgs under partner\\n        const directOrgs = await queryOrgsByPartnerId(adminUser.partnerId);\\n\\n        // Get all clients under partner\\n        const clients = await queryClientsByPartnerId(adminUser.partnerId);\\n\\n        // Get orgs for each client\\n        const clientOrgPromises = clients.map((client) =>\\n          queryOrgsByClientId(client.clientId)\\n        );\\n        const clientOrgsArrays = await Promise.all(clientOrgPromises);\\n        const clientOrgs = clientOrgsArrays.flat();\\n\\n        // Merge and deduplicate\\n        const allOrgIds = new Set([\\n          ...directOrgs.map((o) => o.orgId),\\n          ...clientOrgs.map((o) => o.orgId),\\n        ]);\\n        return await batchGetOrgs(Array.from(allOrgIds));\\n      }\\n\\n      // ClientAdmin: Get orgs by clientId\\n      if (adminUser.clientId) {\\n        return await queryOrgsByClientId(adminUser.clientId);\\n      }\\n\\n      return [];\\n\\n    case \\"SuperAdmin\\":\\n      return await batchGetOrgs(adminUser.allowedOrgIds);\\n\\n    default:\\n      return [];\\n  }\\n}\\n\\nasync function canManageClients(adminUser: AdminUser): Promise<boolean> {\\n  if (adminUser.userRole === \\"VardaCareAdmin\\") return true;\\n  if (adminUser.userRole === \\"ClientAdmin\\") {\\n    // Only PartnerAdmin (with partnerId) can manage clients\\n    return !!adminUser.partnerId;\\n  }\\n  return false;\\n}\\n\\nasync function canCreateOrg(adminUser: AdminUser): Promise<boolean> {\\n  return (\\n    adminUser.userRole === \\"VardaCareAdmin\\" ||\\n    adminUser.userRole === \\"ClientAdmin\\"\\n  );\\n}\\n\\nasync function createOrg(\\n  adminUser: AdminUser,\\n  orgData: CreateOrgInput\\n): Promise<Organization> {\\n  // Auto-assign partnerId/clientId based on creator\\n  if (adminUser.userRole === \\"ClientAdmin\\") {\\n    if (adminUser.partnerId) {\\n      // PartnerAdmin creating org\\n      orgData.partnerId = adminUser.partnerId;\\n      // orgData.clientId can be specified or null for direct org\\n    } else if (adminUser.clientId) {\\n      // ClientAdmin creating org\\n      const client = await getClient(adminUser.clientId);\\n      orgData.partnerId = client.partnerId; // Required\\n      orgData.clientId = adminUser.clientId;\\n    }\\n  }\\n\\n  const org = await insertOrg(orgData);\\n  return org;\\n}","type":"text","styles":{}}],"children":[]},{"id":"3cf60558-99ac-47d8-b8b3-ec74e6af8d55","type":"divider","props":{},"children":[]},{"id":"0a34394a-d5b4-4fbd-8ef2-92d2997236e6","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Design Decision: Why No org_access Table?","type":"text","styles":{}}],"children":[]},{"id":"403862c4-91c1-474f-a202-c6ee1d2589d7","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Question: Why don''t we need an ","type":"text","styles":{}},{"text":"org_access","type":"text","styles":{"code":true}},{"text":" table for Partner/Client access?","type":"text","styles":{}}],"children":[]},{"id":"138bbca5-1c5a-47ff-8fbf-77fbd23f8b9e","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Answer","type":"text","styles":{"bold":true}},{"text":": Because access is determined hierarchically through the relationships already stored in the Organization table.","type":"text","styles":{}}],"children":[]},{"id":"6d6b8ae1-cb2e-4ffd-bcad-2082faabb7dd","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Hierarchical Access Model","type":"text","styles":{}}],"children":[]},{"id":"a8883772-3acb-451a-bd8c-35eff52d9a3f","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"The system uses a ","type":"text","styles":{}},{"text":"hierarchical access model","type":"text","styles":{"bold":true}},{"text":" where:","type":"text","styles":{}}],"children":[]},{"id":"d5ae0d57-5571-4948-8425-95c30a7dee4d","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Each ","type":"text","styles":{}},{"text":"Organization","type":"text","styles":{"bold":true}},{"text":" has a ","type":"text","styles":{}},{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" (required) and optionally a ","type":"text","styles":{}},{"text":"clientId","type":"text","styles":{"code":true}}],"children":[]},{"id":"fa4e7fbd-7a7d-4f3b-abec-6233eb715ac3","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Each ","type":"text","styles":{}},{"text":"Client","type":"text","styles":{"bold":true}},{"text":" has a ","type":"text","styles":{}},{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" (required)","type":"text","styles":{}}],"children":[]},{"id":"82b6a21d-b345-4f2e-99ad-15c246cdd7a4","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Access is determined by these direct relationships, not by separate access grants","type":"text","styles":{}}],"children":[]},{"id":"c3b5a415-eb19-4ee6-bae7-cce8a8a0bd45","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Access Determination","type":"text","styles":{}}],"children":[]},{"id":"ff9def97-318e-426c-8fa5-f30597ef655a","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"PartnerAdmin Access","type":"text","styles":{}}],"children":[]},{"id":"363a2422-52f2-4b21-9e42-3fedfc124331","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"A PartnerAdmin can access an organization if:","type":"text","styles":{}}],"children":[]},{"id":"e270c421-12c9-4666-ab7b-d86665102eac","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Direct access","type":"text","styles":{"bold":true}},{"text":": ","type":"text","styles":{}},{"text":"org.partnerId === user.partnerId","type":"text","styles":{"code":true}},{"text":" (org belongs directly to partner)","type":"text","styles":{}}],"children":[]},{"id":"e14c79f8-6fb5-4c50-a448-9dc42197f0b1","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Indirect access","type":"text","styles":{"bold":true}},{"text":": ","type":"text","styles":{}},{"text":"org.clientId","type":"text","styles":{"code":true}},{"text":" exists AND ","type":"text","styles":{}},{"text":"client.partnerId === user.partnerId","type":"text","styles":{"code":true}},{"text":" (org belongs to a client under the partner)","type":"text","styles":{}}],"children":[]},{"id":"addae170-6a2a-46fa-bd0e-5f6458ae8f43","type":"codeBlock","props":{"language":"typescript"},"content":[{"text":"// PartnerAdmin access check\\nconst org = await getOrg(orgId);\\nif (org.partnerId === user.partnerId) {\\n  return true; // Direct access\\n}\\nif (org.clientId) {\\n  const client = await getClient(org.clientId);\\n  return client.partnerId === user.partnerId; // Indirect access via client\\n}","type":"text","styles":{}}],"children":[]},{"id":"735a6a58-59cc-47c0-9cee-9183a06759a2","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"ClientAdmin Access","type":"text","styles":{}}],"children":[]},{"id":"d022b7a1-3c74-4410-b876-e609cecf089f","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"A ClientAdmin can access an organization if:","type":"text","styles":{}}],"children":[]},{"id":"2b9a860b-2d80-43df-b7f9-a0b1f2c68e0d","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Direct access","type":"text","styles":{"bold":true}},{"text":": ","type":"text","styles":{}},{"text":"org.clientId === user.clientId","type":"text","styles":{"code":true}},{"text":" (org belongs to the client)","type":"text","styles":{}}],"children":[]},{"id":"ee6fb4d8-3e1e-4053-8b36-e653bbae976d","type":"codeBlock","props":{"language":"typescript"},"content":[{"text":"// ClientAdmin access check\\nconst org = await getOrg(orgId);\\nreturn org.clientId === user.clientId;","type":"text","styles":{}}],"children":[]},{"id":"06acdbf0-2c2e-4a6b-b363-bbd21efdd4c6","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Why This Works Without org_access","type":"text","styles":{}}],"children":[]},{"id":"b14776ab-46eb-4bc4-bd93-533cb9312172","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Single Source of Truth","type":"text","styles":{"bold":true}},{"text":": The ","type":"text","styles":{}},{"text":"org.clientId","type":"text","styles":{"code":true}},{"text":" and ","type":"text","styles":{}},{"text":"org.partnerId","type":"text","styles":{"code":true}},{"text":" fields in the Organization table are the source of truth for access","type":"text","styles":{}}],"children":[]},{"id":"3c959a80-ef21-47cf-8cf2-0ed2d320d138","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"No Many-to-Many Relationships","type":"text","styles":{"bold":true}},{"text":": Each org belongs to ","type":"text","styles":{}},{"text":"exactly one","type":"text","styles":{"bold":true}},{"text":" partner and ","type":"text","styles":{}},{"text":"at most one","type":"text","styles":{"bold":true}},{"text":" client","type":"text","styles":{}}],"children":[]},{"id":"2f4ab372-bfb8-4705-bce0-05da38e6a93b","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Hierarchical Relationships","type":"text","styles":{"bold":true}},{"text":": Partner → Client → Org relationship is already defined","type":"text","styles":{}}],"children":[]},{"id":"63702e61-92ee-4b0e-be09-e08af80d88ff","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Simpler Queries","type":"text","styles":{"bold":true}},{"text":": Direct GSI queries on Organization table by ","type":"text","styles":{}},{"text":"partnerId","type":"text","styles":{"code":true}},{"text":" or ","type":"text","styles":{}},{"text":"clientId","type":"text","styles":{"code":true}}],"children":[]},{"id":"aae64157-be1d-4ec5-8de2-f472cfc422d9","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Performance","type":"text","styles":{}}],"children":[]},{"id":"678ce9b8-00db-4d1a-a32e-e486f1818b8f","type":"heading","props":{"level":4,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"PartnerAdmin - Get All Orgs","type":"text","styles":{}}],