"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Very efficient: Single GSI query","type":"text","styles":{}}],"children":[]},{"id":"27ae56ec-c91e-46f2-a966-89f1ddb9a912","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Benefits of Hierarchical Model","type":"text","styles":{}}],"children":[]},{"id":"e9fd090c-66ae-42fc-91bd-f363ecaa7e06","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Simplicity","type":"text","styles":{"bold":true}},{"text":": No additional ","type":"text","styles":{}},{"text":"org_access","type":"text","styles":{"code":true}},{"text":" table to maintain","type":"text","styles":{}}],"children":[]},{"id":"04ce1d28-aecc-48d1-b0bf-752ac569ff55","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Data Integrity","type":"text","styles":{"bold":true}},{"text":": Relationships are explicit and enforced","type":"text","styles":{}}],"children":[]},{"id":"37fec32e-bf94-4f57-8542-f4b19284e775","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Performance","type":"text","styles":{"bold":true}},{"text":": Direct GSI queries are faster than join table queries","type":"text","styles":{}}],"children":[]},{"id":"9c48e049-6aa1-4b36-98d7-328b3bfd827d","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Consistency","type":"text","styles":{"bold":true}},{"text":": Single source of truth eliminates sync issues","type":"text","styles":{}}],"children":[]},{"id":"c2fef3f0-6eb4-4f20-af19-a1b4a6eef8e6","type":"numberedListItem","props":{"textColor":"default","textAlignment":"left","backgroundColo