36:28.781137+00', 'text', '[{"id":"075f26c7-fb0f-4c17-b8e0-33153f37cd9a","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Untitled","type":"text","styles":{}}],"children":[]},{"id":"b708cb3d-658e-4e97-8160-9e51e0622b22","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[],"children":[]},{"id":"e965c3f0-e039-47a8-adcd-9196dd6837a9","type":"heading","props":{"level":1,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"SUMMARY RESUME:","type":"text","styles":{}}],"children":[]},{"id":"6f8a089c-4010-4cec-a7fc-4a7484915d3d","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"\\"Transforming business potential by bridging behavioral insights, optimized processes, and strategic software solutions.\\"","type":"text","styles":{"bold":true}}],"children":[]},{"id":"20093025-bbac-4403-bf6d-8beb6a859c7d","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[],"children":[]},{"id":"960c290b-33d5-460e-b034-9dd5413f4dfc","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"\\"Transforming business potential through behavioral insights, refined process design, and forward-thinking software strategy.\\"","type":"text","styles":{"bold":true}}],"children":[]},{"id":"70f0d1d4-e197-478e-b342-78199e62f249","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Dynamic and strategic leader with over 5 years of experience in high-touch client engagement, staff management, and operational excellence within luxury and creative environments. Proven success in optimizing customer journeys, managing cross-functional teams, and driving revenue through service innovation and workflow enhancements.\\nAdept at designing inclusive visitor experiences, managing public-facing staff, and leveraging data to improve satisfaction and performance. Passionate about art, design, and using storytelling to shape world-class guest experiences.","type":"text","styles":{}}],"children":[]},{"id":"40395b21-d95b-4e35-8f85-5ed7f33baeb2","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Dynamic and strategic leader with over 5 years of experience in optimizing operations within luxury and creative environments. Proven ability to enhance client engagement and operational excellence by managing frontline teams and scheduling for seamless visitor experiences. Recognized for driving revenue growth through service innovation, workflow enhancements, and leveraging data analytics to improve operational performance. Aiming to further advance career by implementing effective strategies that elevate customer journeys and team dynamics.","type":"text","styles":{}}],"children":[]},{"id":"adbdbb67-99f6-4a3c-8527-aee9c09ad176","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Dynamic and strategic leader with over 6 years of experience with high-end, customer-facing environments across the luxury, art, and design industries. Proven track record for optimizing operations, and leveraging behavioral insights to drive measurable business outcomes. committed to creating meaningful, human-centered experiences killed in leveraging software systems and data strategies to streamline operations, Fluent in French, Italian, and English.","type":"text","styles":{}}],"children":[]},{"id":"17ded666-10a4-45ca-ad86-96c525aad245","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Vision-driven marketing leader with 6+ years of experience at the intersection of ","type":"text","styles":{}},{"text":"luxury textiles, interior design, and high-end home furnishings","type":"text","styles":{"bold":true}},{"text":". I bring a rare blend of creative intuition and business acumen—fueling ","type":"text","styles":{}},{"text":"brand elevation, digital growth, and strategic market expansion","type":"text","styles":{"bold":true}},{"text":" in design-forward industries. With a deep respect for the craftsmanship behind interiors and materials, I’ve built my career around helping brands tell richer stories, reach the right audience, and scale intelligently.\\nMy work is rooted in ","type":"text","styles":{}},{"text":"customer-centric, data-informed strategy","type":"text","styles":{"bold":true}},{"text":"—from full-funnel performance marketing to digital storytelling that turns browsers into loyal brand advocates. I’ve consistently delivered growth by ","type":"text","styles":{}},{"text":"optimizing the customer journey","type":"text","styles":{"bold":true}},{"text":", refining messaging across platforms, and creating immersive digital touchpoints that speak to the discerning tastes of interior designers and luxury buyers.\\nI thrive in environments where ","type":"text","styles":{}},{"text":"aesthetics and analytics meet","type":"text","styles":{"bold":true}},{"text":"—where brand positioning, UX-led design, and content cadence come together to drive both creative impact and measurable revenue. Passionate about pushing the textile and interiors space forward, I’m focused on building future-facing marketing ecosystems that are as intentional as the materials we celebrate.","type":"text","styles":{}}],"children":[]},{"id":"ac348776-44dc-4596-90eb-90bdfba8b93b","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[],"children":[]}]', '{}', '{}', 'text', '3', '[{"x":-40,"y":202,"id":"link-0","type":"document",