'2026-02-22 10:08:23.190968+00', 'text', '[]', '{}', '{}', 'text', '1', '[]'), ('730', 'muzl28t1', 'Untitled', '0', '2026-02-22 17:26:51.044154+00', '2026-02-22 17:26:51.044154+00', 'text', '[]', '{}', '{}', 'text', '1', '[]'), ('731', '2flkgwsx', 'Untitled', '0', '2026-02-22 19:37:19.772073+00', '2026-02-22 19:37:19.772073+00', 'text', '[]', '{}', '{}', 'text', '1', '[]'), ('732', 'xh3xl765', 'Untitled', '0', '2026-02-23 10:38:47.284914+00', '2026-02-23 10:39:08.822637+00', 'text', '[{"id":"1d94e1ae-0541-40d7-b010-84137643fb5f","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Untitled","type":"text","styles":{}}],"children":[]},{"id":"104c76ba-ec62-4e2d-8d17-cbed23c56a05","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"/","type":"text","styles":{}}],"children":[]},{"id":"0ca21d73-efc5-4695-84fc-4a5eda6ba205","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[],"children":[]}]', '{}', '{}', 'text', '1', '[]'), ('733', 'z7kaejzg', 'Untitled', '0', '2026-02-23 13:20:51.292847+00', '2026-02-23 13:20:51.292847+00', 'text', '[]', '{}', '{}', 'text', '1', '[]'), ('734', '3ao18xyy', 'Untitled', '0', '2026-02-23 13:21:45.230335+00', '2026-02-23 13:21:45.230335+00', 'text', '[]', '{}', '{}', 'text', '1', '[]'), ('735', 'pvw3x1kb', 'Untitled', '0', '2026-02-23 13:22:22.944137+00', '2026-02-23 13:22:22.944137+00', 'text', '[]', '{}', '{}', 'text', '1', '[]'), ('736', 's97ejhkw', 'Untitled', '0', '2026-02-23 13:23:01.001+00', '2026-02-23 13:23:01.001+00', 'text', '[]', '{}', '{}', 'text', '1', '[]'), ('737', 'i7hiq1vc', 'Untitled', '0', '2026-02-23 13:23:01.391897+00', '2026-02-23 13:23:01.391897+00', 'text', '[]', '{}', '{}', 'text', '1', '[]'), ('738', 'bf80l534', 'Untitled', '0', '2026-02-23 13:23:03.346523+00', '2026-02-23 13:25:37.716608+00', 'text', '[{"id":"820fa409-5dc6-4e5e-b788-b283154e012b","type":"heading","props":{"level":1,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Método Kroma","type":"text","styles":{}}],"children":[]},{"id":"4b140dfa-e92a-447a-8b2d-2664b863c115","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"O ","type":"text","styles":{}},{"text":"Método Kroma","type":"text","styles":{"bold":true}},{"text":" é um framework de decisão cromática focado em UI Design para produtos digitais. Ele prioriza a ","type":"text","styles":{}},{"text":"Hierarquia de Luminância","type":"text","styles":{"bold":true}},{"text":" (contraste entre camadas) e a ","type":"text","styles":{}},{"text":"Intencionalidade Semântica","type":"text","styles":{"bold":true}},{"text":" (significado da cor), garantindo que a estética nunca comprometa a usabilidade ou a conversão.","type":"text","styles":{}}],"children":[]},{"id":"7676b4eb-0aae-45dd-b3bd-2070e25995e3","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"O método divide a seleção de cores em 4 etapas lógicas: ","type":"text","styles":{}},{"text":"Fundação","type":"text","styles":{"bold":true}},{"text":", ","type":"text","styles":{}},{"text":"Interação","type":"text","styles":{"bold":true}},{"text":", ","type":"text","styles":{}},{"text":"Estrutura","type":"text","styles":{"bold":true}},{"text":" e ","type":"text","styles":{}},{"text":"Feedback","type":"text","styles":{"bold":true}},{"text":".","type":"text","styles":{}}],"children":[]},{"id":"4c1536d7-7b30-415f-801f-24b80b39e0c2","type":"divider","props":{},"children":[]},{"id":"d8b81e97-848e-4c52-b5e1-8aa7dbcd593e","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"1. Definição da Fundação (Cores Principais)","type":"text","styles":{}}],"children":[]},{"id":"4e7a8632-fc81-4591-8bd5-3d47f16cc621","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"A escolha depende do modelo de aplicação (Modelo 01 ou 02). O objetivo é definir o tom da marca e o tom da conversão.","type":"text","styles":{}}],"children":[]},{"id":"7aedd34c-978d-4ecd-9653-0b57da73414d","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Para Modelo 01 (Primária e Realce Separados)","type":"text","styles":{}}],"children":[]},{"id":"db0fc12a-ab85-466c-bea3-a0af4a9e79b1","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Ideal para marcas que possuem uma cor institucional forte, mas que não funciona bem para botões (ex: muito clara, muito escura ou sem contraste).","type":"text","styles":{}}],"children":[]},{"id":"e2825253-cae0-4613-b243-a9e89e0fbeb8","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Primária:","type":"text","styles":{"bold":true}},{"text":" A cor da identidade (Logo). Usada em cabeçalhos, ícones institucionais e detalhes decorativos.","type":"text","styles":{}}],"children":[]},{"id":"d4bd41c8-4b61-489b-b9f3-daad2954ec0a","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Realce (Action):","type":"text","styles":{"bold":true}},{"text":" A cor da conversão (Botão). Deve ter alto contraste com o fundo e se destacar da Primária. Geralmente uma cor complementar ou um tom mais saturado/escuro da primária.","type":"text","styles":{}}],"children":[]},{"id":"5606b6b7-236b-43ad-a6e3-5049abf628df","type":"heading","props":{"level":3,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Para Modelo 02 (Primária/Realce Unificados)","type":"text","styles":{}}],"children":[]},{"id":"19adfe91-e633-47fb-8230-1c9f966633ed","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Ideal para marcas minimalistas ou \\"Tech\\", onde a cor da marca é vibrante e possui excelente leitura para botões.","type":"text","styles":{}}],"children":[]},{"id":"9e7d1e25-924a-43cf-85ed-3d97f5c4c86e","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Primária/Realce:","type":"text","styles":{"bold":true}},{"text":" A mesma cor assume o papel de Branding e Conversão.","type":"text","styles":{}}],"children":[]},{"id":"0fd373aa-2877-4919-81a4-e31e1d2a73b0","type":"divider","props":{},"children":[]},{"id":"0d221aea-4d2b-4ff3-a94e-30aa745aec52","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"2. Definição de Interação (Hovers)","type":"text","styles":{}}],"children":[]},{"id":"25d2680a-5ae8-484c-9851-7615540496ba","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Cores não existem estaticamente; elas respondem ao usuário.","type":"text","styles":{}}],"children":[]},{"id":"a31f2fa9-19bb-4026-8de4-e7117e7b3b7f","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Hover Realce:","type":"text","styles":{"bold":true}},{"text":" Calcule entre ","type":"text","styles":{}},{"text":"10% a 20% de escurecimento","type":"text","styles":{"bold":true}},{"text":" (redução de luminosidade) da cor de ","type":"text","styles":{}},{"text":"Realce","type":"text","styles":{"italic":true}},{"text":".","type":"text","styles":{}}],"children":[{"id":"a2c02a05-6b94-4870-8c12-17f431717e09","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Por que escurecer?","type":"text","styles":{"italic":true}},{"text":" Simula a física de um botão sendo pressionado (sombra/profundidade). Clarear o botão no hover muitas vezes faz ele parecer \\"desativado\\".","type":"text","styles":{}}],"children":[]}]},{"id":"6b5a2bae-fad5-4efe-9571-5fdfcc87b629","type":"divider","props":{},"children":[]},{"id":"695f591d-4231-4b4e-8719-4bd339355151","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"3. Definição de Estrutura (Ambientes)","type":"text","styles":{}}],"children":[]},{"id":"1f58ee07-966a-478b-a3f1-fa677e8107a6","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Aqui definimos o \\"palco\\" onde o conteúdo acontece. Evitamos absolutos (preto #000 e branco #FFF) nos fundos para reduzir fadiga ocular.","type":"text","styles":{}}],"children":[]},{"id":"0aa330d8-277b-420a-be6a-eec3b655abe5","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Secundária/Invertida (Background Light):","type":"text","styles":{"bold":true}},{"text":" Um cinza muito claro (\\"Off-white\\").","type":"text","styles":{}}],"children":[{"id":"9254e418-bc8c-404b-ab71-8b794cf44bd2","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Dica Kroma:","type":"text","styles":{"italic":true}},{"text":" Adicione 2% a 5% de tinta da cor Primária ou Azul para \\"esfriar\\" o cinza, ou Amarelo para \\"esquentar\\". Nunca use cinza neutro sujo.","type":"text","styles":{}}],"children":[]}]},{"id":"335f1c22-6587-4f10-896f-619d34039e64","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Texto/Invertida (Cor de Leitura):","type":"text","styles":{"bold":true}},{"text":" Um cinza muito escuro ou azul profundo (\\"Off-black\\").","type":"text","styles":{}}],"children":[{"id":"0c96c938-68de-459a-a927-e9c352dc71c3","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Regra:","type":"text","styles":{"italic":true}},{"text":" Deve ter contraste suficiente (WCAG AA ou AAA) sobre o fundo claro. Evite #000000 puro para não causar vibração visual.","type":"text","styles":{}}],"children":[]}]},{"id":"27037236-dafb-429f-8b9b-2dc98c51f9cb","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Bloco White:","type":"text","styles":{"bold":true}},{"text":" ","type":"text","styles":{}},{"text":"Branco Puro (#FFFFFF).","type":"text","styles":{"bold":true}}],"children":[{"id":"1f1bf17f-2348-4656-863a-2167df4b508d","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Uso:","type":"text","styles":{"italic":true}},{"text":" Aplicado sobre o fundo ","type":"text","styles":{}},{"text":"Secundária/Invertida","type":"text","styles":{"italic":true}},{"text":" para criar \\"Cards\\" ou áreas de conteúdo. A diferença sutil entre o fundo cinza claro e o bloco branco cria elevação natural.","type":"text","styles":{}}],"children":[]}]},{"id":"a76b9c1e-c75e-4cf0-9401-d6acd2618518","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Borda White:","type":"text","styles":{"bold":true}},{"text":" Um cinza neutro de transição.","type":"text","styles":{}}],"children":[{"id":"113e6a43-15d6-4760-b5e5-1bbb78c0abb3","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Lógica:","type":"text","styles":{"italic":true}},{"text":" Deve ser escuro o suficiente para ser visto no Bloco White, mas claro o suficiente para não parecer uma grade de prisão.","type":"text","styles":{}}],"children":[]}]},{"id":"ed61858e-963d-455a-80f9-98eb77988773","type":"divider","props":{},"children":[]},{"id":"671e1597-560f-4e52-89dd-bce550425de5","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"4. Definição de Profundidade (Dark Mode / Blocos Escuros)","type":"text","styles":{}}],"children":[]},{"id":"105ebef7-c29f-4009-b3ef-83200ea2d4c0","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Como a interface se comporta em áreas escuras ou modos noturnos.","type":"text","styles":{}}],"children":[]},{"id":"b52c411c-aa56-4b04-9365-3febbb6ab7b6","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Bloco Black:","type":"text","styles":{"bold":true}},{"text":" A cor de superfície escura.","type":"text","styles":{}}],"children":[{"id":"f6a42316-9beb-4f21-967e-152264f41154","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Regra:","type":"text","styles":{"italic":true}},{"text":" Nunca use preto puro. Use uma versão muito escura da cor Primária (ex: Azul Marinho Profundo) ou um Cinza Chumbo. Deve ser ","type":"text","styles":{}},{"text":"mais claro","type":"text","styles":{"bold":true}},{"text":" que a cor de fundo (caso exista um fundo global preto) para simular proximidade com a luz.","type":"text","styles":{}}],"children":[]}]},{"id":"2807a895-4146-4fa4-9aeb-7db6ca2accee","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Borda Black:","type":"text","styles":{"bold":true}},{"text":" A linha de definição.","type":"text","styles":{}}],"children":[{"id":"28270fd3-0737-4829-9ed9-b7f8eb72df6c","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Opção A (Corporativo):","type":"text","styles":{"italic":true}},{"text":" Um tom 15% mais claro que o Bloco Black.","type":"text","styles":{}}],"children":[]},{"id":"2acc3e2e-52fb-4b9a-94b1-7c55eb6a6813","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Opção B (Tech/Neon):","type":"text","styles":{"italic":true}},{"text":" Uma cor vibrante (Ciano, Primária) com baixa opacidade ou espessura fina, criando efeito de luz.","type":"text","styles":{}}],"children":[]}]},{"id":"695fe268-b65b-4742-876b-f58aa37f3ff2","type":"divider","props":{},"children":[]},{"id":"95e8efe1-7aa4-47df-920c-5f4c262353f5","type":"heading","props":{"level":2,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"5. Definição de Feedback (Semântica)","type":"text","styles":{}}],"children":[]},{"id":"94ff7283-f7f4-4c01-badd-60698c8a915b","type":"paragraph","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Cores que comunicam o estado do sistema.","type":"text","styles":{}}],"children":[]},{"id":"3733dc9c-d48e-4169-b740-3724e9c01ccf","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Sucesso:","type":"text","styles":{"bold":true}},{"text":" Verde.","type":"text","styles":{}}],"children":[{"id":"235de677-d8dc-4b64-9943-b5e117bf668f","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Ajuste:","type":"text","styles":{"italic":true}},{"text":" Se a marca já é Verde, use o ","type":"text","styles":{}},{"text":"próprio tom da marca","type":"text","styles":{"italic":true}},{"text":" (para reforçar branding). Se a marca não é verde, use um \\"Verde Esmeralda\\" (sóbrio) ou \\"Verde Neon\\" (tech) que combine com a saturação da paleta.","type":"text","styles":{}}],"children":[]}]},{"id":"7399d674-fbd0-4887-b8e5-ed7bd4bf0b7a","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Hover Sucesso:","type":"text","styles":{"bold":true}},{"text":" Escurecimento de 10% a 15% da cor de Sucesso.","type":"text","styles":{}}],"children":[]},{"id":"9d03fba4-d0eb-46b4-8c0e-b7d9f61a5e14","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Alerta:","type":"text","styles":{"bold":true}},{"text":" Vermelho, Laranja ou Âmbar.","type":"text","styles":{}}],"children":[{"id":"762988eb-d432-4533-9452-7894cf3fd2b6","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Regra de Ouro:","type":"text","styles":{"italic":true}},{"text":" O Alerta deve contrastar com a Primária.","type":"text","styles":{}}],"children":[]},{"id":"089a6513-68aa-48a6-90aa-9034d41a0f2d","type":"bulletListItem","props":{"textColor":"default","textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Exemplo:","type":"text","styles":{"italic":true}},{"text":" Se a Primária é Laranja, o Alerta ","type":"text","styles":{}},{"text":"deve","type":"text","styles":{"bold":true}},{"text":" ser Vermelho (para não confundir). Se a Primária é Azul, o Alerta pode ser Laranja ou Âmbar.","type":"text","styles":{}}],"children":[]}]},{"id":"8abddb21-fdd2-49c8-8106-c2b4fcb6458e","type":"divider","props":{},"children":[]},{"id":"635da267-773a-4f3a-b6a0-8987c9048bfb","type":"heading","props":{"level":1,"textColor":"default","isToggleable":false,"textAlignment":"left","backgroundColor":"default"},"content":[{"text":"Exemplo Prático de Aplicação",